OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied in this function are global for this page

   if(IsProject()==0)

   {

      CString parentWnd;

      parentWnd.SetString("wszyscy.bdf");

   }



   CString plikWAV;

   plikWAV.SetString("wszysc");



   int constSpriteID = 6;



      // Zmienna informujaca ile dany wiersz ma zwrotek.

   int maxZwrotek = 4;



      // left - dlugosc trwania zwrotki podczas nagrywania

      // top  - odleglosc zwrotki od poczatku

      // right - czy byla nagrywana 0 - nie, 1 - tak

   CRect zwrotki[maxZwrotek];



   int const_zw = -99;

   zwrotki[0].SetRect( 44100*12, 0, 0, 0 );

   zwrotki[1].SetRect( 44100*8, const_zw, 0, 0 );

   zwrotki[2].SetRect( 44100*11, 2*const_zw, 0, 0 );

   zwrotki[3].SetRect( 44100*11, 3*const_zw, 0, 0 );





      // Zmienna informujaca, ktory fragment tekstu jest aktywny

   int biezacaZwrotka = -1;



      // Zmienna informujac, ze odbywa sie obecnie nagrywanie

   int nagrywanie = 0;



      // Ogrywanie calego wiersza

   int grajWszystko = 0;



      // Zmienna informujaca, ze ma miejsce odtwarzanie jednej zwrotki

   int odtwarzanie = 0;



      // Zmienna informujaca, czy wszystkie zwrotki zostaly nagrane.

      // 0 - tak, > 0  - nie

   int wszystkieNagrane = maxZwrotek;



   CRect progress;

   progress.SetRect( 547, 435, 288+115, 229 );





   int ikona0=0;

   int const_help=5000;

   char status_txt=0;      //0-stop, 1-play, 2-pause, 

   int pomoc = 0;



   LoadGroup("g_rec.grp");



   CRect progress;

   progress.SetRect( 547, 435, 288+115, 229 );

   Group.Sprite_Holder.MoveTo( 3, progress.left, progress.top );



   int toolbar=0;

   int toolbarCase=0;

   Group.HotSpot_Holder.DisableHotSpot(1);



   int indexGlob = constSpriteID+maxZwrotek;

   while( indexGlob <= 31 )

   {

      Group.Sprite_Holder.MoveTo( indexGlob, 700, 0 );

      indexGlob++;

   }



   SetCursor(4);

   ZliczNagraneZwrotki();

   FadeScreen(1,1000);

   //SetTimer (const_help);

}





void OnTimer(void)

{

	// Add your timer handler code here

   SetTimer(0);

   Sound_Holder.Stop(0);

   Group.Sound_Holder.PlayDSound(0);

}







void OnKeyDown(UINT nChar)

{

	// Add your keyboard handler code here

}







void OnClosePage(void)

{

	// Add your close page handler code here

   grajWszystko = 0;

   Recorder.Stop();

   Recorder.CloseFile();



   FadeScreen(0,1000);

   CloseGroup();

}









