void Group.Sprite_Holder.MouseMoveIn(int spriteID)

{

   if(spriteID>32)

   {

      if(toolbar)  SetCursor(0);

      return;

   }





   if( PobierzAktywnoscPrzycisku( spriteID ) == 0 ) 

      return;



   switch( spriteID )

   {

      case 2:   //odtwarzanie bufora

         if( zwrotki[biezacaZwrotka].right == 0) 

            return;

         break;

   }

   SetCursor(0);

}





void Group.Sprite_Holder.MouseMoveOut(int spriteID)

{

   SetCursor(4);   

}





