void Recorder.Progress(int percentFull)

{

   float prog = 0.64*percentFull;



   // Przesuniecie wskaznika nagrywania o zadana wartosc.

   Group.Sprite_Holder.MoveTo( 3, progress.left+prog, progress.top );

}







